/* Test driver */
public class Main {
    public static void main(String[] args) {
        ElevatorSystem system = new ElevatorSystem(1, 10);
        Request r = new Request(0, 5);
        Elevator e = system.handleRequest(r);
        if (e == null) { System.out.println("FAIL_NO_ASSIGN"); System.exit(1); }
        System.out.println("ASSIGNED_" + e.getId());
        for (int i = 0; i < 6; i++) system.step();
        if (e.getCurrentFloor() == 5 && !e.hasStops()) {
            System.out.println("REACHED_DEST");
        } else {
            System.out.println("WRONG_FLOOR_" + e.getCurrentFloor());
        }
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ElevatorSystem system = new ElevatorSystem(2, 10);
        system.setMaintenance(0, true);
        Elevator e = system.handleRequest(new Request(0, 4));
        if (e != null && e.getId() == 2) {
            System.out.println("SKIPPED_MAINT");
        } else {
            System.out.println("FAIL_PICKED_" + (e == null ? "null" : e.getId()));
        }
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ElevatorSystem system = new ElevatorSystem(1, 10);
        system.setStrategy(new LOOKStrategy());
        system.handleRequest(new Request(0, 7));
        system.handleRequest(new Request(2, 5));
        system.stepN(15);
        if (system.allIdle()) {
            System.out.println("ALL_IDLE_OK");
        } else {
            System.out.println("STILL_BUSY");
        }
        Elevator e = system.getElevator(0);
        System.out.println("FINAL_FLOOR_" + e.getCurrentFloor());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ElevatorSystem system = new ElevatorSystem(1, 10);
        Elevator e = system.handleRequest(new Request(0, 8));
        System.out.println("STATE_INIT_" + e.getState());
        system.step();
        System.out.println("STATE_RUN_" + e.getState());
        for (int i = 0; i < 12; i++) system.step();
        System.out.println("STATE_END_" + e.getState());
        if (e.getState() == ElevatorState.IDLE && !e.hasStops()) {
            System.out.println("FINISHED_OK");
        }
    }
}
